module.exports=[498854,a=>{"use strict";a.s(["CommunicationCharterClient",()=>b]);let b=(0,a.i(211857).registerClientReference)(function(){throw Error("Attempted to call CommunicationCharterClient() from the server but CommunicationCharterClient is on the client. It's not possible to invoke a client function from the server, it can only be rendered as a Component or passed to props of a Client Component.")},"[project]/src/app/(dashboard)/communication-charter/CommunicationCharterClient.tsx <module evaluation>","CommunicationCharterClient")},656030,a=>{"use strict";a.s(["CommunicationCharterClient",()=>b]);let b=(0,a.i(211857).registerClientReference)(function(){throw Error("Attempted to call CommunicationCharterClient() from the server but CommunicationCharterClient is on the client. It's not possible to invoke a client function from the server, it can only be rendered as a Component or passed to props of a Client Component.")},"[project]/src/app/(dashboard)/communication-charter/CommunicationCharterClient.tsx","CommunicationCharterClient")},877606,a=>{"use strict";a.i(498854);var b=a.i(656030);a.n(b)},616416,a=>{"use strict";var b=a.i(907997),c=a.i(794431),d=a.i(999472);a.i(570396);var e=a.i(673727),f=a.i(877606);let g={ACCOUNTS:{department:"ACCOUNTS",title:"Accounts Communication Charter",subtitle:"Guidelines for payment follow-ups, invoicing, and dispute resolution",metrics:[{label:"Invoice Response",value:"24 hrs",description:"Respond to invoice queries within 24 hours"},{label:"Payment Follow-up",value:"3 days",description:"Follow up on pending payments after 3 days of due date"},{label:"Dispute Resolution",value:"48 hrs",description:"Acknowledge and begin resolving disputes within 48 hours"},{label:"Monthly Statements",value:"5th",description:"Send monthly statements by 5th of each month"}],sections:[{title:"Payment Communication",rules:["Always maintain a professional, polite tone even when following up on overdue payments","Provide clear payment breakdowns and reference invoice numbers in all communications","Offer multiple payment options and flexibility where company policy allows","Escalate to manager if payment is 30+ days overdue before sending formal notices","Document all payment-related conversations in the CRM immediately"]},{title:"Invoice Management",rules:["Send invoices within 24 hours of project milestone completion","Include all necessary details: GST, project reference, payment terms","Follow up with receipt confirmation within 2 business days","Maintain a tracking sheet for all outstanding invoices"]},{title:"Dispute Handling",rules:["Listen fully before responding - never interrupt or dismiss client concerns","Acknowledge the issue and provide a timeline for resolution","Loop in relevant team members (Sales/Operations) for service-related disputes","Document the dispute resolution process for future reference","Follow up after resolution to ensure client satisfaction"]}],dos:["Use invoice numbers and clear references in all communications","Acknowledge receipt of payments promptly with thank you messages","Provide proactive updates on payment processing status","Maintain detailed records of all financial conversations","Offer payment plans for large amounts when appropriate","Be empathetic to client cash flow challenges while maintaining boundaries"],donts:["Never threaten legal action without manager approval","Do not discuss financial details over unsecured channels","Avoid using aggressive language in payment reminders","Never share one client's payment details with another client","Do not make payment arrangement promises without authority","Never delay invoice disputes - address them immediately"],caseStudies:[{id:"acc-1",title:"Late Payment Follow-up",scenario:"A long-term client is 15 days overdue on a ₹2.5L invoice. They've been reliable in the past but haven't responded to the standard payment reminder.",correctResponse:'"Hi [Client Name], I hope this message finds you well. I noticed payment for invoice #INV-2024-156 dated [date] for ₹2,50,000 is pending. I understand things can get busy - is there anything I can help with to expedite this? We value our partnership and want to ensure there are no blockers. Please let me know if you\'d like to discuss a payment schedule. Happy to hop on a quick call."',wrongResponse:'"Your payment is overdue. Please pay immediately to avoid service disruption and late fees."',keyTakeaway:"Maintain relationships while being clear about expectations. Offer solutions, not ultimatums."},{id:"acc-2",title:"Invoice Dispute Resolution",scenario:"A client disputes charges for additional work, claiming they never approved the extra scope. The work was done based on verbal approval from their marketing manager.",correctResponse:'"Hi [Client Name], Thank you for bringing this to our attention. I\'ve reviewed the project timeline and found that the additional work was initiated on [date] following a discussion with [Marketing Manager Name]. I understand there may have been a communication gap on your end. Let me share the email trail and call notes. To resolve this, we can either: 1) Include this in your next project at a 15% discount, or 2) Adjust the current invoice with a 10% goodwill credit. What works best for you?"',wrongResponse:'"The work was approved by your team. We have records. You need to pay the full amount."',keyTakeaway:"Document everything, but prioritize resolution over being right. Offer options that protect both parties."},{id:"acc-3",title:"VIP Client Escalation",scenario:"An Enterprise tier client's CFO directly emails complaining about \"billing inconsistencies\" and threatens to review the entire contract. This is the first you're hearing of any issue.",correctResponse:'"Dear [CFO Name], Thank you for reaching out directly. I take this feedback very seriously. I will personally audit the past 6 months of invoices and have a detailed reconciliation report ready within 48 hours. Our founders, Arush and Nishu, have been informed and would like to schedule a call with you at your earliest convenience to discuss this and any other concerns. In the meantime, I\'m pausing any pending invoices until we resolve this. My direct line is [number] - please feel free to call anytime."',wrongResponse:"\"I'll look into it and get back to you\" or CC'ing multiple people without acknowledging the severity.",keyTakeaway:"Enterprise escalations require immediate senior involvement. Over-communicate and demonstrate urgency."}]},SOCIAL:{department:"SOCIAL",title:"Social Media Communication Charter",subtitle:"Guidelines for content approval, client feedback, and crisis management",metrics:[{label:"Content Approval",value:"24 hrs",description:"Get content approved at least 24 hours before posting"},{label:"Comment Response",value:"2 hrs",description:"Respond to comments/DMs within 2 hours during business hours"},{label:"Performance Reports",value:"Weekly",description:"Send performance summaries every Monday"},{label:"Crisis Response",value:"30 min",description:"Acknowledge crises within 30 minutes, escalate immediately"}],sections:[{title:"Content Approval Process",rules:["Send content calendars minimum 1 week in advance for client review","Include visual mockups, captions, hashtags, and posting times","Use the designated approval channel (email/Slack) - not WhatsApp for approvals","Track approval status and send reminders 48 hours before posting deadline","Document all feedback and revisions in the content tracker"]},{title:"Client Feedback Handling",rules:["Acknowledge all feedback within 4 hours, even if just confirming receipt","Separate subjective preferences from strategic concerns in your response","Provide data-backed recommendations when pushing back on feedback","Never argue with the client - present alternatives professionally","Document recurring feedback patterns for strategy reviews"]},{title:"Crisis Communication",rules:["Do NOT respond to crises without manager approval","Screenshot and document the crisis before any action","Prepare 3 response options for review within 1 hour","Monitor sentiment during and after crisis response","Conduct post-crisis review within 24 hours"]}],dos:["Use brand voice consistently across all responses","Proactively share trending opportunities with clients","Document all community management actions","Celebrate client wins and milestones promptly","Maintain a swipe file of successful content formats",'Send unexpected "great job" messages when content performs well'],donts:["Never post without final approval","Do not engage with trolls or provocative comments","Avoid using personal opinions in brand responses","Never delete negative comments without manager approval","Do not share client analytics with third parties","Never use the same content across different clients"],caseStudies:[{id:"soc-1",title:"Handling Negative Comments",scenario:"A customer posts a negative review on the client's Instagram post, claiming poor product quality. Other followers are starting to engage with the comment.",correctResponse:'"Hi [User], we\'re sorry to hear about your experience. We take product quality very seriously. Could you please DM us your order details? Our team would love to make this right for you. We appreciate you bringing this to our attention." Then immediately: DM the user, inform client POC, and prepare resolution options.',wrongResponse:'Deleting the comment, ignoring it, or replying defensively: "Our products are of the highest quality. You must have misused it."',keyTakeaway:"Turn complaints into opportunities. Public empathy + private resolution = brand trust."},{id:"soc-2",title:"Content Revision Conflicts",scenario:'The client\'s marketing manager requests extensive changes to an approved content calendar, citing "new brand direction." The changes would require 20+ hours of additional work with no scope revision.',correctResponse:"\"Hi [Manager Name], thank you for sharing the updated direction! I've reviewed the changes and I'm excited about where the brand is heading. For transparency, these revisions represent significant additional work (~20 hours). I have two options: 1) We can implement priority changes within the current scope and phase in the rest next month, or 2) I can prepare a quick change order for [amount] to cover the additional work. Which approach works better for your timeline and budget?\"",wrongResponse:'"This is outside scope. We can\'t do this without additional payment" or simply agreeing and working overtime.',keyTakeaway:'Acknowledge positively, quantify impact, and offer options. Never just say "no" or silently absorb scope creep.'},{id:"soc-3",title:"Performance Decline Conversation",scenario:"A client's engagement has dropped 40% over the past month. They're asking what's going wrong before the scheduled monthly review.",correctResponse:"\"Hi [Client Name], I noticed you're looking at the numbers - I was planning to address this in our call but happy to share context now. We've seen a 40% dip in engagement, which aligns with: 1) Algorithm changes affecting similar accounts in your industry, 2) The reduced posting frequency last week due to the approval delays. Here's my plan: [specific 3-point action plan]. I'd love to discuss this further - can we move our review call to tomorrow? I want to ensure we're aligned on the recovery strategy.\"",wrongResponse:'"It\'s the algorithm" or waiting until the scheduled call to address it.',keyTakeaway:"Own the conversation proactively. Provide context, take accountability, and present solutions."}]},SEO:{department:"SEO",title:"SEO Communication Charter",subtitle:"Guidelines for technical reporting, ranking updates, and client education",metrics:[{label:"Ranking Reports",value:"Bi-weekly",description:"Send ranking position updates every 2 weeks"},{label:"Technical Issues",value:"24 hrs",description:"Report critical technical issues within 24 hours of discovery"},{label:"Algorithm Updates",value:"48 hrs",description:"Communicate algorithm update impacts within 48 hours"},{label:"Monthly Reviews",value:"5th",description:"Deliver comprehensive monthly reports by 5th of each month"}],sections:[{title:"Performance Reporting",rules:["Use visual dashboards - avoid raw data dumps","Always contextualize numbers: YoY, MoM, and industry benchmarks","Highlight wins prominently, but don't hide declines","Include actionable next steps in every report","Record Loom videos for complex technical explanations"]},{title:"Ranking Communications",rules:["Never guarantee specific rankings or timelines","Explain ranking fluctuations with patience and context","Use competitor comparisons to show relative progress","Celebrate ranking wins, even small ones","Document all ranking-related conversations"]},{title:"Technical Communication",rules:["Translate technical jargon into business impact","Provide estimated effort and timelines for technical fixes","Coordinate with Web team for implementation timelines","Create simple checklists for client-side technical requirements","Follow up on technical implementations within 1 week"]}],dos:["Use analogies to explain complex SEO concepts","Provide regular education on SEO fundamentals","Share relevant case studies and industry news","Celebrate traffic milestones with the client","Document all technical recommendations formally","Set realistic expectations from day one"],donts:["Never make ranking guarantees or timeline promises","Avoid technical jargon without explanation","Do not blame Google updates without evidence","Never implement changes without client knowledge","Avoid comparing to competitors without context","Never ignore client questions - always respond thoughtfully"],caseStudies:[{id:"seo-1",title:"Ranking Drop Communication",scenario:"A client's primary keyword dropped from position 3 to position 12 after a Google update. They're concerned and asking for explanations.",correctResponse:"\"Hi [Client Name], I saw the ranking shift this morning and was already analyzing it. Here's what happened: Google rolled out a core update on [date], and we're seeing industry-wide fluctuations. Your drop from #3 to #12 for [keyword] is significant but not uncommon post-update. The good news: 1) Our technical foundation is solid, 2) Three of your other priority keywords actually improved, 3) Historically, we've recovered from updates within 4-6 weeks. My immediate action plan: [3 specific steps]. Let's schedule a call to discuss - I have some proactive strategies that could help us recover faster.\"",wrongResponse:'"This is Google\'s algorithm update. Nothing we can do but wait" or ignoring the issue hoping rankings recover.',keyTakeaway:"Proactive communication, context, and a clear action plan turn anxiety into confidence."},{id:"seo-2",title:"Explaining Algorithm Updates",scenario:"A non-technical client is confused about a Google core update and its potential impact on their business. They want to understand what's happening.",correctResponse:'"Think of Google like a restaurant reviewer who occasionally updates their criteria. Yesterday, they valued ambiance heavily; today, they might prioritize food quality more. Our website is like your restaurant - fundamentally strong. This update is Google re-prioritizing what matters. What this means for us: 1) Some rankings may shift temporarily, 2) Sites with thin content may struggle, 3) Our content strategy already aligns with the new priorities. I\'ve prepared a one-page summary of the update and our position. Would you prefer a quick call or should I send it over?"',wrongResponse:'Sending a technical explanation full of jargon or dismissing their concern with "don\'t worry about it."',keyTakeaway:"Use analogies and simple language. Make complex topics accessible and show you're on top of it."},{id:"seo-3",title:"Managing Timeline Expectations",scenario:"A new client expects to rank #1 for a competitive keyword within 2 months. They were promised this by their previous agency.",correctResponse:"\"I appreciate your ambitious goals! Let me share what realistic SEO timelines look like: For [keyword], which has a difficulty score of 78/100, industry data shows 6-12 months for page 1 rankings. Here's why: [brief explanation]. Rather than focusing only on one keyword, here's my strategy: Month 1-2: Target 10 long-tail keywords (achievable wins). Month 3-4: Mid-competition keywords. Month 6+: Build toward [primary keyword]. This approach typically delivers faster ROI while building toward your big goal. I'll show you case studies from similar clients. If the previous agency promised #1 in 2 months, I'd be concerned about their methods. Shall I elaborate?\"",wrongResponse:'Agreeing to unrealistic timelines or simply saying "that\'s not possible" without alternatives.',keyTakeaway:"Educate with evidence, offer achievable milestones, and subtly highlight red flags from competitors."}]},ADS:{department:"ADS",title:"Ads Communication Charter",subtitle:"Guidelines for budget management, campaign reporting, and performance optimization",metrics:[{label:"Daily Monitoring",value:"Daily",description:"Check campaign performance daily, flag anomalies immediately"},{label:"Budget Alerts",value:"80%",description:"Alert clients when 80% of monthly budget is consumed"},{label:"Performance Reports",value:"Weekly",description:"Send performance summaries every Friday"},{label:"Optimization Updates",value:"48 hrs",description:"Communicate significant optimizations within 48 hours"}],sections:[{title:"Budget Management",rules:["Never exceed approved budget without explicit client approval","Alert clients at 50%, 80%, and 100% budget utilization","Provide spending projections for the remaining month","Document all budget change requests formally","Recommend budget adjustments based on performance data"]},{title:"Performance Reporting",rules:["Focus on business outcomes, not just ad metrics","Always include ROI/ROAS calculations","Compare against benchmarks and previous periods","Highlight successful experiments and learnings","Include clear recommendations for the next period"]},{title:"Campaign Communication",rules:["Get creative approval before campaigns go live","Share A/B test results with insights, not just numbers","Explain targeting decisions and audience strategies","Communicate platform changes that affect campaigns","Maintain a learning log of what works per client"]}],dos:["Proactively suggest budget optimizations","Share competitor ad intelligence (where available)","Celebrate wins with specific revenue impact","Document all campaign changes and rationale","Provide early warnings for underperforming campaigns","Use screenshots and visuals in reports"],donts:["Never overspend without approval","Do not hide underperforming campaigns","Avoid making excuses for poor performance","Never launch campaigns without creative approval","Do not promise specific ROI numbers","Never compare clients against each other"],caseStudies:[{id:"ads-1",title:"Budget Overrun Scenario",scenario:"Due to a bidding strategy change, you've accidentally spent 130% of the monthly budget with 5 days remaining. The client hasn't been informed yet.",correctResponse:"\"Hi [Client Name], I need to bring something to your attention immediately. Due to an aggressive bidding adjustment made on [date] to capitalize on high-conversion periods, we've consumed 130% of the monthly budget. This resulted in [X] additional conversions at [Y] cost per conversion. I take full responsibility for not catching this earlier. My proposed resolution: 1) We absorb the 20% overage as a goodwill gesture, 2) I've paused campaigns to prevent further spend, 3) I've implemented daily budget alerts to prevent this in future. Would you prefer a call to discuss?\"",wrongResponse:"Waiting until the end of month to report, making excuses about platform glitches, or simply invoicing the overage without context.",keyTakeaway:"Own mistakes immediately. Transparency + accountability + solution = maintained trust."},{id:"ads-2",title:"Poor Campaign Performance",scenario:"A campaign has been running for 3 weeks with 50% below target ROAS. The client is expecting the weekly report.",correctResponse:"\"Hi [Client Name], Here's your weekly report. I want to address the elephant in the room: we're at 2.1x ROAS against our 4x target. Here's my analysis: 1) Creative fatigue set in faster than expected - CTR dropped 40% after week 1, 2) Our highest-intent audiences are saturated, 3) The competitor [X] launched aggressive discounting. Actions taken this week: Refreshed 3 ad creatives, expanded to lookalike audiences, tested new ad placements. Projected timeline: If new creatives perform as expected, we should see improvement by end of Week 4. If not, I recommend we pivot to [alternative strategy]. Let's discuss this in our Friday call.\"",wrongResponse:'"ROAS is below target. We\'re working on it" or over-explaining with technical details to deflect.',keyTakeaway:"Be direct about underperformance. Show you understand why and have a plan."},{id:"ads-3",title:"Client ROI Expectations",scenario:"A new client expects 10x ROAS on a ₹50,000/month budget in a competitive e-commerce category. Industry average is 3-4x.",correctResponse:"\"Thank you for sharing your goals! Let me provide some context based on our experience. In the [industry] category, here's what we typically see: New accounts in month 1-2: 2-3x ROAS (learning phase), Months 3-4: 4-5x ROAS (optimization phase), Mature accounts: 5-6x ROAS (some clients exceed this). 10x ROAS is achievable, but typically requires: Higher budget for more data, 4-6 months of optimization, Strong offers/differentiators. Here's my recommended approach: Let's start with a 4x target, hit that consistently, then scale toward 10x with proven winning strategies. I'd rather under-promise and over-deliver. How does this approach feel?\"",wrongResponse:'Agreeing to unrealistic targets or simply saying "that\'s impossible."',keyTakeaway:"Set achievable targets with clear progression paths. Use industry data to educate."}]},WEB:{department:"WEB",title:"Web Development Communication Charter",subtitle:"Guidelines for bug reports, progress updates, and client demos",metrics:[{label:"Bug Response",value:"4 hrs",description:"Acknowledge critical bugs within 4 hours"},{label:"Progress Updates",value:"Bi-weekly",description:"Send progress updates every 2 weeks"},{label:"Staging Updates",value:"24 hrs",description:"Push staging updates and notify within 24 hours"},{label:"Demo Scheduling",value:"48 hrs",description:"Schedule demos at least 48 hours in advance"}],sections:[{title:"Bug Communication",rules:["Acknowledge all bug reports within 4 hours","Categorize bugs by severity: Critical, High, Medium, Low","Provide estimated fix timelines for Critical/High bugs","Document bug resolution steps for client reference","Follow up after fixes to confirm resolution"]},{title:"Progress Updates",rules:["Use visual progress indicators (% complete, screenshots)","Highlight blockers and dependencies clearly","Align updates with project milestones","Include next steps and upcoming deliverables","Record video walkthroughs for complex features"]},{title:"Demo & Handoff",rules:["Prepare demo environments 24 hours in advance","Create demo scripts covering all key features","Document known limitations or pending items","Provide training materials for client teams","Schedule post-launch support windows"]}],dos:["Use Loom videos for bug explanations and demos","Maintain a public project board for transparency","Proactively communicate potential delays","Document technical decisions for future reference","Celebrate milestone completions with clients","Offer multiple revision rounds within scope"],donts:["Never push to production without staging approval","Do not promise fix timelines you can't meet","Avoid technical jargon without explanation","Never blame other vendors publicly",'Do not ignore "small" client requests',"Never assume requirements - always clarify"],caseStudies:[{id:"web-1",title:"Critical Bug Discovery",scenario:"You discover a payment gateway bug that has been silently failing 10% of transactions for the past 2 days. The client doesn't know yet.",correctResponse:'"[URGENT] Hi [Client Name], I\'m calling regarding a critical issue I just identified. Our monitoring detected that approximately 10% of payment transactions have been failing silently since [date]. Immediate actions taken: 1) Temporarily switched to backup payment flow, 2) Identified and fixed the root cause - deploying in 2 hours, 3) Generated a list of affected transactions (attached). Impact assessment: ~[X] failed transactions, approximately ₹[Y] in potentially lost revenue. Recommended recovery: I suggest we email affected customers with a "we\'re sorry" discount code. I\'m available for a call right now. This is our top priority."',wrongResponse:"Fixing quietly without informing the client, or sending an email instead of calling for critical issues.",keyTakeaway:"Critical issues require immediate calls, not emails. Lead with actions taken, not apologies."},{id:"web-2",title:"Scope Creep Management",scenario:'During development, the client requests a "small change" that would actually require 3 days of additional work. The request comes via WhatsApp.',correctResponse:"\"Hi [Client Name], Thanks for the idea! The [feature] integration is definitely doable. For transparency, here's what it involves: Development time: ~3 days, Testing: 1 day, Documentation: 0.5 days. This puts it outside our current sprint scope. Options: 1) Add to Phase 2 (no additional cost if scope allows), 2) Fast-track it now for ₹[X] with delivery by [date], 3) Swap it with an existing feature of similar complexity. I'd recommend Option 1 to maintain our launch timeline, but happy to discuss. Let me know your preference and I'll update the project board.\"",wrongResponse:'"Sure, no problem!" (absorbing scope) or "That\'s outside scope" (without alternatives).',keyTakeaway:"Acknowledge positively, quantify effort, and always offer options."},{id:"web-3",title:"Deadline Miss Communication",scenario:"The project is going to miss the deadline by 1 week due to unforeseen API integration complexity. The deadline is in 3 days.",correctResponse:"\"Hi [Client Name], I need to discuss our launch timeline. We've encountered unexpected complexity with the [X] API integration - their documentation didn't cover [specific issue]. Current status: 85% complete. Required additional time: 5-7 business days. Here's my proposal: 1) Launch the site without the [X] feature on the original date, add it in Phase 1.5 (recommended), 2) Push the entire launch by 1 week to include everything, 3) Use a temporary workaround for [X] and replace it post-launch. I should have flagged this risk earlier. Going forward, I'm adding integration buffer time to all projects. What works best for your business needs?\"",wrongResponse:"Waiting until the deadline day to communicate, or making excuses without solutions.",keyTakeaway:"Communicate delays early, take accountability, and always offer alternatives."}]},HR:{department:"HR",title:"HR Communication Charter",subtitle:"Guidelines for employee queries, policy communication, and sensitive discussions",metrics:[{label:"Query Response",value:"24 hrs",description:"Respond to employee queries within 24 hours"},{label:"Policy Updates",value:"1 week",description:"Communicate policy changes 1 week before implementation"},{label:"Feedback Delivery",value:"48 hrs",description:"Deliver feedback within 48 hours of incidents"},{label:"Exit Process",value:"Same day",description:"Initiate exit process communication same day"}],sections:[{title:"Employee Communication",rules:["Maintain confidentiality in all communications","Use private channels for sensitive discussions","Document all formal communications in employee records","Follow up on commitments within stated timelines","Be approachable and empathetic in all interactions"]},{title:"Policy Communication",rules:["Announce policy changes with context and rationale","Provide written documentation for all policies","Allow Q&A period before policy implementation","Create summary documents for complex policies","Track policy acknowledgments systematically"]},{title:"Sensitive Communication",rules:["Always have a witness for disciplinary conversations","Prepare talking points before difficult conversations","Focus on behaviors, not personalities","Document all sensitive conversations immediately","Provide support resources when delivering difficult news"]}],dos:["Be consistent in policy application","Listen actively during employee conversations","Follow up on concerns raised in meetings","Celebrate employee milestones and achievements","Provide regular check-ins with new hires","Maintain open door policy genuinely"],donts:["Never discuss one employee's issues with another","Avoid making promises you can't keep","Do not delay difficult conversations","Never dismiss employee concerns","Avoid inconsistent policy application","Never share salary details inappropriately"],caseStudies:[{id:"hr-1",title:"Policy Violation Discussion",scenario:"An employee has been consistently late (15-30 mins) for the past 2 weeks. Their work quality is good, but the behavior is noticeable to the team.",correctResponse:"\"[Private meeting] Hi [Employee], I wanted to chat about something I've noticed. Over the past two weeks, you've been arriving 15-30 minutes late fairly consistently. I'm not here to lecture - I want to understand if there's something going on that we can help with. Is everything okay at home? Are there any scheduling challenges we should discuss? [Listen]. I appreciate you sharing. Here's what we need to work on: [expectations]. Let's check in again next week. I'm confident we can sort this out together.\"",wrongResponse:"Public call-outs, sending a formal warning email without conversation, or ignoring the behavior entirely.",keyTakeaway:"Address issues privately, lead with curiosity not judgment, and balance empathy with expectations."},{id:"hr-2",title:"Leave Conflict Resolution",scenario:"Two team members have requested the same dates off (Diwali week). The team needs at least one person available. Both have already made plans.",correctResponse:"\"Hi [Employee 1] and [Employee 2], I see you both have requested Diwali week off, which is completely understandable! Unfortunately, we need coverage during this period. Before I decide, I want to give you both agency here. Here are some options: 1) One person takes Diwali week, the other gets an extended break before/after, 2) Split the week with overlapping WFH flexibility, 3) I can offer the person who adjusts an extra compensatory day off. Could you two discuss and let me know what works? If you can't agree, I'll make the call based on first-come-first-served, but I'd prefer you collaborate on this.\"",wrongResponse:"Denying both requests or making an arbitrary decision without involving them.",keyTakeaway:"Give employees agency in finding solutions. Fair process matters as much as fair outcome."},{id:"hr-3",title:"Delivering Constructive Feedback",scenario:"A senior employee's attitude has been affecting team morale. Multiple team members have complained, but the employee is unaware.",correctResponse:"\"[Private meeting with witness] Hi [Employee], I value our working relationship and that's exactly why I want to have this conversation. I've received feedback that some of your recent interactions have felt dismissive to teammates. I want to share specific examples: [specific, recent examples]. I'm not sharing this to criticize - I believe you may not realize the impact. You're talented and I want you to succeed here. Can you help me understand your perspective? [Listen actively]. Going forward, here's what I need to see change: [specific behaviors]. I'm happy to support you in this - would regular check-ins help?\"",wrongResponse:'Vague feedback like "people are complaining about your attitude" or avoiding the conversation entirely.',keyTakeaway:"Be specific with examples, make it a conversation, and offer support alongside expectations."}]},SALES:{department:"SALES",title:"Sales Communication Charter",subtitle:"Guidelines for lead response, proposal follow-ups, and negotiation",metrics:[{label:"Lead Response",value:"30 min",description:"Respond to hot leads within 30 minutes"},{label:"Proposal Follow-up",value:"24 hrs",description:"Follow up on proposals within 24 hours of sending"},{label:"Quote Validity",value:"7 days",description:"Communicate quote validity clearly (default 7 days)"},{label:"Lost Deal Feedback",value:"48 hrs",description:"Seek feedback on lost deals within 48 hours"}],sections:[{title:"Lead Communication",rules:["Respond to inbound leads within 30 minutes during business hours","Qualify leads using BANT framework (Budget, Authority, Need, Timeline)",'Send calendar links, don\'t ask "when are you free?"',"Follow up 3 times before marking lead as unresponsive","Document all lead interactions in CRM immediately"]},{title:"Proposal Communication",rules:["Confirm proposal receipt within 24 hours","Address objections within 4 hours of receiving them","Never discount without getting something in return","Create urgency through legitimate value, not pressure","Document all pricing discussions formally"]},{title:"Negotiation Ethics",rules:["Never badmouth competitors","Be transparent about limitations and timelines","Don't overpromise capabilities or results","Get all agreements in writing",'Respect "no" but understand the reasoning']}],dos:["Send personalized follow-ups referencing conversations","Share relevant case studies proactively","Offer value in every interaction (insights, resources)","Be honest about whether you're the right fit","Celebrate closed deals with the team","Thank clients for referrals"],donts:["Never pressure prospects into decisions","Avoid generic templates without personalization","Do not share pricing without qualification","Never promise what operations can't deliver","Avoid ghosting lost deals - always seek feedback","Never speak negatively about previous clients"],caseStudies:[{id:"sales-1",title:"Hot Lead Response",scenario:'A high-value lead fills out the contact form at 3 PM on a Friday. They mentioned they\'re "evaluating agencies for Q2."',correctResponse:"[Call within 15 mins, if no answer, WhatsApp + email within 30 mins]: \"Hi [Name], I just saw your inquiry - perfect timing as I'm available right now for a quick chat. Based on what you shared, it sounds like we could be a great fit for your Q2 goals. I have availability at 4 PM today or Monday 10 AM. Which works better? In the meantime, I've attached a case study from [similar company] that might be relevant. Looking forward to connecting - [Name], Bluefiremedia\" + Calendar link.",wrongResponse:'Waiting until Monday to respond, or sending a generic "Thanks for your interest, we\'ll be in touch" email.',keyTakeaway:"Speed to lead matters. Provide immediate value and make booking a call effortless."},{id:"sales-2",title:"Proposal Rejection Handling",scenario:"A prospect you've been nurturing for 2 months emails saying they're \"going with another agency\" without explanation.",correctResponse:"\"Hi [Name], Thank you for letting me know. While I'm disappointed we won't be working together, I genuinely wish you success with your chosen partner. If you have 2 minutes, I'd really appreciate understanding what influenced your decision - it helps us improve. Was it pricing, timeline, capabilities, or something else? No hard feelings either way. Also, if things don't work out as expected down the line, my door is always open. Wishing you the best - [Name]\" [If they respond with reason, address it for future reference]",wrongResponse:'Not responding, or responding with "Let me match their price" without understanding the objection.',keyTakeaway:"Handle rejection gracefully. Every lost deal is market research."},{id:"sales-3",title:"Pricing Negotiation",scenario:'A qualified prospect loves the proposal but asks for 30% discount, claiming "budget constraints." They\'ve already indicated high intent.',correctResponse:"\"I appreciate you sharing that, [Name]. Our pricing reflects the value and results we deliver - I shared case studies showing [X] ROI for similar clients. That said, I want to make this work. Let me offer some options: 1) Reduce scope to fit budget: We can start with [core services] at [reduced price], adding more services once you see results. 2) Longer commitment discount: A 12-month commitment gets you 15% off. 3) Staggered payment: Same scope, split into monthly installments. What I can't do is simply discount without adjusting scope - that wouldn't be fair to our other clients or set you up for success. Which option interests you?\"",wrongResponse:"Immediately agreeing to 30% off, or refusing any negotiation entirely.",keyTakeaway:"Never discount without getting something in return (scope reduction, longer commitment, case study rights)."}]},OPERATIONS:{department:"OPERATIONS",title:"Operations Communication Charter",subtitle:"Guidelines for cross-team coordination, escalations, and delivery management",metrics:[{label:"Escalation Response",value:"2 hrs",description:"Acknowledge escalations within 2 hours"},{label:"Handoff Completion",value:"24 hrs",description:"Complete sales-to-ops handoffs within 24 hours"},{label:"Status Updates",value:"Daily",description:"Provide daily status updates on active escalations"},{label:"Process Documentation",value:"1 week",description:"Document new processes within 1 week of implementation"}],sections:[{title:"Escalation Management",rules:["Acknowledge all escalations within 2 hours of receipt","Categorize escalations: Client-facing, Internal, Vendor","Assign clear owners for every escalation","Provide daily updates until resolution","Document resolution and preventive measures"]},{title:"Cross-Team Coordination",rules:["Use standardized handoff templates","Include all relevant context in handoffs","Confirm receipt and understanding of handoffs","Flag dependencies and blockers early","Run weekly sync meetings with team leads"]},{title:"Client Delivery",rules:["Track all deliverables in centralized system","Send proactive delay notifications","Quality check deliverables before client handoff","Document client feedback and implement improvements","Maintain SLA tracking dashboards"]}],dos:["Over-communicate during crises","Create playbooks for recurring scenarios","Recognize team members who resolve escalations well","Share learnings from incidents across teams","Maintain strong vendor relationships","Build buffer time into project timelines"],donts:["Never let escalations sit without acknowledgment","Avoid blaming other teams during client calls","Do not promise timelines without team consultation","Never skip documentation for urgent fixes","Avoid single points of failure","Never ignore early warning signs"],caseStudies:[{id:"ops-1",title:"Client Escalation Management",scenario:'A Premium client\'s CEO emails directly to the founders complaining about "consistent delivery issues" across multiple departments. This is the first formal escalation, though there have been smaller complaints.',correctResponse:"[Immediate founder notification + action within 1 hour]: \"Dear [CEO Name], Thank you for your email. Arush and Nishu have asked me to personally oversee this matter. You have my commitment that this will be resolved. Immediate actions taken: 1) Audit of all active deliverables (complete by EOD), 2) Single point of contact assigned: [Ops Manager] (me) - here's my direct number, 3) All-hands meeting scheduled with your account team for tomorrow. I'd like to schedule a call with you within the next 24 hours to discuss findings and our remediation plan. Does [time] work? You deserve better, and we'll make this right.\"",wrongResponse:'Defensive responses, CC\'ing multiple people without clear ownership, or waiting until you have "all the facts."',keyTakeaway:"CEO escalations require immediate senior ownership, clear action items, and over-communication."},{id:"ops-2",title:"Cross-Department Conflict",scenario:'The Sales team promised a client "custom reporting dashboard" but Web says it\'s outside scope. Client onboarding is in 2 days. Sales and Web are blaming each other.',correctResponse:"[Emergency sync call]: \"Let's focus on solutions, not blame. Here's the situation: Client expects feature, we have 2 days. Options: 1) [To Sales] Can you manage client expectations with a phased approach - basic dashboard now, custom features in Phase 2 at additional cost? 2) [To Web] What's the minimum viable version we could deliver in 48 hours? 3) [To both] Is there a third-party tool we can integrate as a temporary solution? [Decision made]. Going forward, let's add a technical feasibility check to the sales process. I'll set up a 30-min weekly sync between Sales and Web to prevent this. No blame - let's fix it and learn.\"",wrongResponse:"Taking sides, escalating to founders without attempting resolution, or letting the departments fight it out.",keyTakeaway:"Focus on solutions first, process improvements second. Never take sides in cross-department conflicts."},{id:"ops-3",title:"Delivery Delay Communication",scenario:"Three clients have deliverables due on the same day. One team member is sick, another has a family emergency. You can only deliver 2 out of 3 on time.",correctResponse:"[Immediate prioritization + client communication]: 1) Prioritize by: Client tier, contractual SLA, delay impact. 2) For the delayed client: \"Hi [Client Name], I wanted to reach out proactively. Due to unforeseen team circumstances, your [deliverable] scheduled for tomorrow will be delayed by 1 day. I take full responsibility for this and have personally reviewed what we have so far - quality is strong. To make this right: 1) I'm adding expedited review for your next 2 deliverables, 2) You'll receive the work by [new date] with a Loom video walkthrough. I apologize for the inconvenience and appreciate your understanding.\" 3) Document and add redundancy for future.",wrongResponse:"Not communicating until the deadline, making generic excuses, or promising all 3 and delivering poor quality.",keyTakeaway:"When you can't deliver everything, prioritize and communicate proactively. Never surprise clients with delays."}]}};function h(){return Object.keys(g)}async function i(){let a=await (0,c.getServerSession)(d.authOptions);a||(0,e.redirect)("/login");let i=a.user.role,j=(a.user.department||"OPERATIONS").toUpperCase(),k=["SUPER_ADMIN","MANAGER"].includes(i),l=h().includes(j)?j:"OPERATIONS";g[l.toUpperCase()];let m=h();return(0,b.jsx)(f.CommunicationCharterClient,{initialDepartment:l,canViewAll:k,allDepartments:m,userName:a.user.name||"User"})}a.s(["default",0,i],616416)},413821,a=>{a.n(a.i(616416))}];

